"use strict";parserFactory.register("coronatranslation.com",()=>new CoronatranslationParser);class CoronatranslationParser extends Parser{constructor(){super()}async getChapterUrls(r,e){return(await this.walkTocPages(r,CoronatranslationParser.chaptersFromDom,CoronatranslationParser.nextTocPageUrl,e)).reverse()}static chaptersFromDom(r){return[...r.querySelectorAll("h2.post-title a")].map(r=>util.hyperLinkToChapter(r))}static nextTocPageUrl(r){let e=r.querySelector("div.wp-pagenavi a.nextpostslink");return null===e?null:e.href}findContent(r){return r.querySelector("div.entry")}extractTitleImpl(r){return r.querySelector("h1")}findChapterTitle(r){return r.querySelector("h1.post-title")}getInformationEpubItemChildNodes(){return[]}}